using UnityEngine;

public class SpriteMovement : MonoBehaviour
{
    public float moveSpeed = 5f; // The speed at which the sprite moves

    private bool isDragging = false; // Flag to indicate if dragging is in progress
    private Vector2 fingerStartPosition; // The starting position of the finger drag

    private Rigidbody2D rb; // Reference to the Rigidbody2D component

    // Start is called before the first frame update
    private void Start()
    {
        rb = GetComponent<Rigidbody2D>(); // Get the Rigidbody2D component attached to the sprite object
    }

    // Update is called once per frame
    private void Update()
    {
        if (Input.touchCount > 0) // Check for touch input
        {
            Touch touch = Input.GetTouch(0); // Get the first touch

            switch (touch.phase)
            {
                case TouchPhase.Began: // When touch begins
                    fingerStartPosition = touch.position; // Store the starting position
                    break;
                case TouchPhase.Moved: // When touch moves
                    Vector2 dragDirection = touch.position - fingerStartPosition; // Calculate the direction of drag

                    if (!isDragging && Mathf.Abs(dragDirection.x) > Mathf.Abs(dragDirection.y))
                    {
                        isDragging = true; // Set dragging flag to true if the x-drag is more significant than y-drag
                    }
                    else if (isDragging)
                    {
                        float moveX = Mathf.Clamp(dragDirection.x, -1f, 1f); // Limit the value to -1 to 1

                        Vector2 movement = new Vector2(moveX, 0f); // Create a movement vector

                        rb.velocity = movement * moveSpeed; // Update the velocity of the sprite's Rigidbody2D component
                    }
                    break;
                case TouchPhase.Ended: // When touch ends
                    isDragging = false; // Reset dragging flag
                    rb.velocity = Vector2.zero; // Stop the sprite movement
                    break;
            }
        }
    }
}
```

In this modified script, when the user touches the screen and starts dragging, the script calculates the drag direction based on the touch position. If the x-drag is more significant than the y-drag, it sets the `isDragging` flag to `true`. Once `isDragging` is `true`, the script limits the x-value of the drag direction to a range of -1 to 1 and converts it into a movement vector to update the sprite's velocity along the x-axis.

Please keep in mind that this modified script assumes that you are using a touch input method, such as on mobile devices. If you want to use mouse input instead, you can replace the relevant lines of code with appropriate mouse input detection.

